(function(w){"use strict";const ID="cylinder-volume";function compute(x){const r=Number(x.radius),h=Number(x.height);if(!Number.isFinite(r)||!Number.isFinite(h)||r<0||h<0)return{error:"0 이상의 반지름과 높이를 입력해 주세요."};return{value:Math.PI*r*r*h};}
function render(root,api){root.innerHTML=`<div class="hm-calc-panel"><div class="hm-calc-form"><div class="hm-calc-grid-2"><div class="hm-calc-field"><label>반지름</label><input class="hm-calc-input" inputmode="decimal" data-key="radius" placeholder="" value=""></div><div class="hm-calc-field"><label>높이</label><input class="hm-calc-input" inputmode="decimal" data-key="height" placeholder="" value=""></div></div><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">계산하기</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div></div>`;const inputs=Array.prototype.slice.call(root.querySelectorAll("input[data-key]")),go=root.querySelector("button"),msg=root.querySelector(".hm-calc-message"),res=root.querySelector(".hm-calc-result");go.addEventListener("click",()=>{const x={};inputs.forEach(i=>x[i.dataset.key]=api.parseNumber(i.value));const r=compute(x);if(r.error){api.setMessage(msg,r.error);api.clearResult(res);return}api.setMessage(msg,"");api.setResult(res,api.resultCard("원기둥 부피",api.formatNumber(r.value,10),"V = πr²h"));});}
w.HM_CALC.register(ID,{compute,render});})(window);
